arguments.command:
cd /tmp && mkdir -p stackalloc-test && cd stackalloc-test && cat > Program.cs << 'EOF'
using System;

Span<nint> nints = stackalloc nint[4];
nints[0] = 42;
nints[1] = nint.MaxValue;
nints[2] = nint.MinValue;
nints[3] = (nint)123456789;

Console.WriteLine($"Span<nint> length: {nints.Length}");
for (int i = 0; i < nints.Length; i++)
    Console.WriteLine($"  [{i}] = {nints[i]}");

Span<nuint> nuints = stackalloc nuint[3];
nuints[0] = 0;
nuints[1] = nuint.MaxValue;
nuints[2] = (nuint)987654321;

Console.WriteLine($"Span<nuint> length: {nuints.Length}");
for (int i = 0; i < nuints.Length; i++)
    Console.WriteLine($"  [{i}] = {nuints[i]}");

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");
EOF
dotnet new console --force -n stackalloc-test --output . > /dev/null 2>&1 && cp Program.cs . && dotnet run

